	private Optional<FactorCostEstimate> estimateLmdbFactorCost(TupleExpr factor, String[] variableNames,
			long boundVarMask, double knownOutputRows, boolean collectMetrics,
			Map<String, Set<Value>> finiteBindingValues, JoinFactorCostModel.EstimationTier estimationTier) {
		if (factor == null) {
			return Optional.empty();
		}
		return estimateScopedMaskFactorCost(factor, boundVarMask, knownOutputRows, collectMetrics,
				finiteBindingValues, estimationTier,
				() -> estimateLmdbFactorCostUncached(factor, variableNames, boundVarMask, knownOutputRows,
						collectMetrics, finiteBindingValues));
	}

	private Optional<FactorCostEstimate> estimateLmdbFactorCostUncached(TupleExpr factor, String[] variableNames,
			long boundVarMask, double knownOutputRows, boolean collectMetrics) {
		return estimateLmdbFactorCostUncached(factor, variableNames, boundVarMask, knownOutputRows, collectMetrics,
				Map.of());
	}

	private Optional<FactorCostEstimate> estimateLmdbFactorCostUncached(TupleExpr factor, String[] variableNames,
			long boundVarMask, double knownOutputRows, boolean collectMetrics,
			Map<String, Set<Value>> finiteBindingValues) {
		if (factor instanceof Join join) {
			return estimateJoinFactorCost(join, boundVariableMaskSet(variableNames, boundVarMask));
		}
		double outputRows = isFiniteNonNegative(knownOutputRows) ? knownOutputRows
				: estimateFactorOutputRows(factor, variableNames, boundVarMask);
		if (!Double.isFinite(outputRows) || outputRows < 0.0d) {
			return Optional.empty();
		}

		SketchBasedJoinEstimator.AccessShape accessShape = sketchBasedJoinEstimator
				.accessShapeForJoinOrdering(factor, variableNames, boundVarMask);
		Optional<FactorCostEstimate> finiteLookupEstimate = estimateFiniteBindingLookupCost(factor, accessShape,
				outputRows, finiteBindingValues, collectMetrics);
		if (finiteLookupEstimate.isPresent()) {
			return finiteLookupEstimate;
		}
		return estimateLmdbFactorCost(outputRows, accessShape, collectMetrics);
	}

	private Optional<FactorCostEstimate> estimateScopedSetFactorCost(TupleExpr factor, Set<String> boundVars,
			double knownOutputRows, boolean collectMetrics, Map<String, Set<Value>> finiteBindingValues,
			JoinFactorCostModel.EstimationTier estimationTier,
			Supplier<Optional<FactorCostEstimate>> estimateSupplier) {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope == null) {
			return estimateSupplier.get();
		}
		Set<String> lookupBoundVars = boundVars == null ? Set.of() : boundVars;
		long knownOutputRowsBits = Double.doubleToLongBits(knownOutputRows);
		Map<String, Set<Value>> finiteValues = emptyFiniteBindingValues(finiteBindingValues);
		JoinFactorCostModel.EstimationTier normalizedTier = estimationTier == null
				? JoinFactorCostModel.EstimationTier.EXACT
				: estimationTier;
		SetFactorCostCacheEntry head = scope.setFactorCostCache.get(factor);
		SetFactorCostCacheEntry previous = null;
		SetFactorCostCacheEntry entry = head;
		while (entry != null) {
			if (entry.matches(lookupBoundVars, knownOutputRowsBits, collectMetrics, finiteValues, normalizedTier)) {
				if (previous != null) {
					previous.next = entry.next;
					entry.next = head;
					scope.setFactorCostCache.put(factor, entry);
				}
				return entry.estimate;
			}
			previous = entry;
			entry = entry.next;
		}
		Optional<FactorCostEstimate> estimate = estimateSupplier.get();
		scope.setFactorCostCache.put(factor,
				new SetFactorCostCacheEntry(FactorCostCacheKey.immutableBoundVars(lookupBoundVars),
						knownOutputRowsBits, collectMetrics, finiteValues, normalizedTier, estimate, head));
		return estimate;
	}

	private Optional<FactorCostEstimate> estimateScopedMaskFactorCost(TupleExpr factor, long boundVarMask,
			double knownOutputRows, boolean collectMetrics, Map<String, Set<Value>> finiteBindingValues,
			JoinFactorCostModel.EstimationTier estimationTier,
			Supplier<Optional<FactorCostEstimate>> estimateSupplier) {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope == null) {
			return estimateSupplier.get();
		}
		long knownOutputRowsBits = Double.doubleToLongBits(knownOutputRows);
		Map<String, Set<Value>> finiteValues = emptyFiniteBindingValues(finiteBindingValues);
		JoinFactorCostModel.EstimationTier normalizedTier = estimationTier == null
				? JoinFactorCostModel.EstimationTier.EXACT
				: estimationTier;
		MaskFactorCostCacheEntry head = scope.maskFactorCostCache.get(factor);
		MaskFactorCostCacheEntry previous = null;
		MaskFactorCostCacheEntry entry = head;
		while (entry != null) {
			if (entry.matches(boundVarMask, knownOutputRowsBits, collectMetrics, finiteValues, normalizedTier)) {
				if (previous != null) {
					previous.next = entry.next;
					entry.next = head;
					scope.maskFactorCostCache.put(factor, entry);
				}
				return entry.estimate;
			}
			previous = entry;
			entry = entry.next;
		}
		Optional<FactorCostEstimate> estimate = estimateSupplier.get();
		scope.maskFactorCostCache.put(factor,
				new MaskFactorCostCacheEntry(boundVarMask, knownOutputRowsBits, collectMetrics, finiteValues,
						normalizedTier, estimate, head));
		return estimate;
	}

	private Map<String, Set<Value>> emptyFiniteBindingValues(Map<String, Set<Value>> finiteBindingValues) {
		if (finiteBindingValues == null || finiteBindingValues.isEmpty()) {
			return Map.of();
		}
		return finiteBindingValues;
	}

	private Object factorFingerprint(TupleExpr factor) {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope == null) {
			return FactorCostCacheKey.factorFingerprint(factor);
		}
		Object fingerprint = scope.factorFingerprintCache.get(factor);
		if (fingerprint == null) {
			fingerprint = FactorCostCacheKey.factorFingerprint(factor);
			scope.factorFingerprintCache.put(factor, fingerprint);
		}
		return fingerprint;
	}

	private boolean hasFiniteBindingValues(Map<String, Set<Value>> finiteBindingValues) {
		if (finiteBindingValues == null || finiteBindingValues.isEmpty()) {
			return false;
		}
		for (Set<Value> values : finiteBindingValues.values()) {
			if (values != null && !values.isEmpty()) {
				return true;
			}
		}
		return false;
	}

	private Optional<FactorCostEstimate> estimateFiniteDerivedJoinSurfaceCost(TupleExpr factor,
			JoinFactorCostModel.CostContext context, FactorCostEstimate baseEstimate) {
		OptimizationCounterSnapshot countersBefore = OptimizationCounterSnapshot.capture(optimizationCostScope.get());
		double comparableBaseWorkRows = comparableBaseWorkRows(factor, context, baseEstimate);
		double comparableBaseOutputRows = comparableBaseOutputRows(context, baseEstimate);
		return estimateFiniteDerivedJoinSurfaceCost(factor, context, baseEstimate,
				comparableBaseWorkRows, comparableBaseOutputRows, countersBefore);
	}

	private Optional<FactorCostEstimate> estimateFiniteDerivedJoinSurfaceCost(TupleExpr factor,
			JoinFactorCostModel.CostContext context, FactorCostEstimate baseEstimate, double comparableBaseWorkRows,
			double comparableBaseOutputRows, OptimizationCounterSnapshot countersBefore) {
		if (context == null || context.getPrefixFactors().isEmpty()) {
			return Optional.empty();
		}
		if (!context.getEstimationTier().allowsExactEstimates()) {
			return Optional.empty();
		}
		return estimateFiniteDerivedJoinSurfaceCost(factor, accessShapeForContext(factor, context),
				context.getFiniteBindingValues(), context.getPrefixFactors(), baseEstimate,
				comparableBaseWorkRows, comparableBaseOutputRows, context.shouldCollectMetrics(), countersBefore);
	}

	private Optional<FactorCostEstimate> estimateFiniteDerivedJoinSurfaceCost(TupleExpr factor,
			SketchBasedJoinEstimator.AccessShape accessShape, Map<String, Set<Value>> finiteBindingValues,
			List<TupleExpr> prefixFactors, FactorCostEstimate baseEstimate, double comparableBaseWorkRows,
			double comparableBaseOutputRows, boolean collectMetrics, OptimizationCounterSnapshot countersBefore) {
		if (sketchBasedJoinEstimator == null || accessShape == null || !hasFiniteBindingValues(finiteBindingValues)
				|| prefixFactors == null || prefixFactors.isEmpty() || factor instanceof BindingSetAssignment) {
			return Optional.empty();
		}
		StatementPattern pattern = accessShape.pattern();
		if (pattern == null || accessShape.joinBoundComponentMask() == 0) {
			return Optional.empty();
		}
		if (prefixFactors.size() + 1 > FINITE_DERIVED_SURFACE_MAX_FACTORS) {
			return Optional.empty();
		}
		if (lookupComponentsAlreadyFinite(accessShape, finiteBindingValues)) {
			return Optional.empty();
		}
		int lookupComponentMask = lookupComponentMaskWithConstants(accessShape, pattern);

		FiniteDerivedSurfaceEstimate bestSurfaceEstimate = null;
		for (Map.Entry<String, Set<Value>> entry : finiteBindingValues.entrySet()) {
			String finiteVarName = entry.getKey();
			Set<Value> finiteValues = entry.getValue();
			if (finiteVarName == null || finiteValues == null || finiteValues.isEmpty()
					|| finiteValues.size() > FINITE_LOOKUP_MAX_COMBINATIONS
					|| factor.getBindingNames().contains(finiteVarName)) {
				continue;
			}
			FiniteDerivedSurfaceEstimate surfaceEstimate = finiteDerivedSurfaceRows(prefixFactors, factor,
					finiteVarName, finiteValues);
			if (surfaceEstimate != null && isFiniteNonNegative(surfaceEstimate.surfaceRows())
					&& (bestSurfaceEstimate == null
							|| surfaceEstimate.surfaceRows() < bestSurfaceEstimate.surfaceRows())) {
				bestSurfaceEstimate = surfaceEstimate;
			}
		}
		if (bestSurfaceEstimate == null || !isFiniteNonNegative(bestSurfaceEstimate.surfaceRows())
				|| bestSurfaceEstimate.surfaceRows() <= 0.0d) {
			return Optional.empty();
		}
		double bestSurfaceRows = bestSurfaceEstimate.surfaceRows();
		double uncappedSurfaceRows = bestSurfaceRows;
		double rowFlowCap = finiteDerivedSurfaceRowFlowCap(bestSurfaceEstimate, baseEstimate);
		if (isFiniteNonNegative(rowFlowCap) && rowFlowCap > 0.0d && rowFlowCap < bestSurfaceRows) {
			bestSurfaceRows = rowFlowCap;
		}

		int invocationCount = finiteDerivedLookupInvocationCount(bestSurfaceRows, bestSurfaceEstimate.prefixRows(),
				bestSurfaceEstimate.branchCount());
		AccessPathEstimate accessPathEstimate = chooseFiniteAccessPath(lookupComponentMask, bestSurfaceRows,
				bestSurfaceRows, invocationCount);
		if (accessPathEstimate == null) {
			return Optional.empty();
		}
		if (accessPathEstimate.missingLookupComponentMask() != 0) {
			return Optional.empty();
		}
		double totalSurfaceWorkRows = Math.max(accessPathEstimate.workRowsPerInvocation(), bestSurfaceRows);
		accessPathEstimate = new AccessPathEstimate(totalSurfaceWorkRows, bestSurfaceRows, bestSurfaceRows,
				accessPathEstimate.indexFieldSequence(), accessPathEstimate.prefixLength(),
				accessPathEstimate.prefixComponentMask(), accessPathEstimate.directLookup(),
				accessPathEstimate.lookupComponentMask(), accessPathEstimate.missingLookupComponentMask(),
				accessPathEstimate.candidateCount());
		if (baseEstimate != null
				&& finiteDerivedEstimateIsWorse(baseEstimate, accessPathEstimate, bestSurfaceRows,
						comparableBaseWorkRows, comparableBaseOutputRows)) {
			return Optional.empty();
		}

		Map<String, String> stringMetrics = new HashMap<>();
		Map<String, Double> doubleMetrics = new HashMap<>();
		stringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_NAME, accessPathEstimate.indexFieldSequence());
		stringMetrics.put(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS,
				componentMaskString(accessPathEstimate.lookupComponentMask()));
		stringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, accessMode(accessPathEstimate));
		if (accessPathEstimate.missingLookupComponentMask() != 0) {
			stringMetrics.put(TelemetryMetricNames.PLANNED_MISSING_LOOKUP_COMPONENTS,
					componentMaskString(accessPathEstimate.missingLookupComponentMask()));
		}
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, "lmdb-finite-derived-surface");
		doubleMetrics.put("plannedSurfaceRows", bestSurfaceRows);
		if (bestSurfaceRows != uncappedSurfaceRows) {
			doubleMetrics.put("plannedUncappedSurfaceRows", uncappedSurfaceRows);
			doubleMetrics.put("plannedSurfaceRowFlowCap", rowFlowCap);
		}
		doubleMetrics.put("plannedPrefixSurfaceRows", bestSurfaceEstimate.prefixRows());
		doubleMetrics.put("plannedSurfaceBranches", (double) bestSurfaceEstimate.branchCount());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_INDEX_PREFIX_LENGTH,
				(double) accessPathEstimate.prefixLength());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS, accessPathEstimate.rowsBeforeFilterAtAccess());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, accessPathEstimate.workRowsPerInvocation());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_PATH_CANDIDATES,
				(double) accessPathEstimate.candidateCount());
		doubleMetrics.put("plannedRepeatedInvocations", (double) invocationCount);
		if (isFiniteNonNegative(bestSurfaceEstimate.prefixRows())) {
			double distinctLookupBindings = bestSurfaceEstimate.prefixRows();
			if (isFiniteNonNegative(bestSurfaceRows)) {
				distinctLookupBindings = Math.min(distinctLookupBindings, Math.max(1.0d, bestSurfaceRows));
			}
			doubleMetrics.put("plannedDistinctLookupBindings", distinctLookupBindings);
		}
		if (collectMetrics && countersBefore != null) {
			countersBefore.addDeltas(doubleMetrics, optimizationCostScope.get());
		}

		double outputRows = bestSurfaceRows;
		return Optional.of(new FactorCostEstimate(accessPathEstimate.workRowsPerInvocation(), outputRows,
				stringMetrics, doubleMetrics, true, accessPathEstimate.directLookup(),
				accessPathEstimate.lookupComponentMask(), accessPathEstimate.missingLookupComponentMask(),
				accessPathEstimate.rowsBeforeFilterAtAccess(), true, true));
	}

	private int finiteDerivedLookupInvocationCount(FiniteDerivedSurfaceEstimate estimate) {
		if (estimate == null) {
			return 1;
		}
		return finiteDerivedLookupInvocationCount(estimate.surfaceRows(), estimate.prefixRows(),
				estimate.branchCount());
	}

	private int finiteDerivedLookupInvocationCount(double surfaceRows, double prefixRows, int branchCount) {
		double invocationRows = surfaceRows;
		if (isFiniteNonNegative(prefixRows)) {
			invocationRows = isFiniteNonNegative(surfaceRows)
					? Math.min(Math.max(1.0d, surfaceRows), Math.max(1.0d, prefixRows))
					: prefixRows;
		}
		if (isFiniteNonNegative(invocationRows)) {
			return (int) Math.max(1L, Math.min(Integer.MAX_VALUE, (long) Math.ceil(invocationRows)));
		}
		return Math.max(1, branchCount);
	}

	private int lookupComponentMaskWithConstants(SketchBasedJoinEstimator.AccessShape accessShape,
			StatementPattern pattern) {
		int lookupComponentMask = accessShape.lookupBoundComponentMask();
		if (pattern != null) {
			lookupComponentMask |= constantComponentMask(pattern);
		}
		return lookupComponentMask;
	}

	private int constantComponentMask(StatementPattern pattern) {
		int constantComponentMask = 0;
		for (Component component : Component.values()) {
			Var componentVar = componentVar(pattern, component);
			if (componentVar != null && componentVar.getValue() != null) {
				constantComponentMask |= componentBit(component);
			}
		}
		return constantComponentMask;
	}

	private double finiteDerivedSurfaceRowFlowCap(FiniteDerivedSurfaceEstimate estimate,
			FactorCostEstimate baseEstimate) {
		if (estimate == null || baseEstimate == null || !isDirectLookup(baseEstimate)) {
			return Double.NaN;
		}
		double prefixRows = estimate.prefixRows();
		if (!isFiniteNonNegative(prefixRows) || prefixRows <= 0.0d) {
			return Double.NaN;
		}
		double rowsPerLookup = baseEstimate.getAccessRowsBeforeFilter();
		if (!isFiniteNonNegative(rowsPerLookup) || rowsPerLookup <= 0.0d) {
			rowsPerLookup = baseEstimate.getOutputRows();
		}
		if (baseEstimate.getMissingLookupComponentMask() != 0 && isFiniteNonNegative(baseEstimate.getOutputRows())) {
			rowsPerLookup = Math.max(rowsPerLookup, baseEstimate.getOutputRows());
		}
		if (!isFiniteNonNegative(rowsPerLookup) || rowsPerLookup <= 0.0d) {
			return Double.NaN;
		}
		double cap = prefixRows * Math.max(1.0d, rowsPerLookup);
		return isFiniteNonNegative(cap) ? cap : Double.NaN;
	}

	private boolean lookupComponentsAlreadyFinite(SketchBasedJoinEstimator.AccessShape accessShape,
			Map<String, Set<Value>> finiteBindingValues) {
		StatementPattern pattern = accessShape.pattern();
		for (Component component : Component.values()) {
			int componentMask = componentBit(component);
			if ((accessShape.lookupBoundComponentMask() & componentMask) == 0) {
				continue;
			}
			Var componentVar = componentVar(pattern, component);
			if (componentVar != null && componentVar.hasValue()) {
				continue;
			}
			String varName = accessShape.joinBoundVarName(component);
			Set<Value> finiteValues = varName == null ? null : finiteBindingValues.get(varName);
			if (finiteValues == null || finiteValues.isEmpty()) {
				return false;
			}
		}
		return true;
	}

	private FiniteDerivedSurfaceEstimate finiteDerivedSurfaceRows(List<TupleExpr> prefixFactors, TupleExpr factor,
			String finiteVarName,
			Set<Value> finiteValues) {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope == null) {
			return finiteDerivedSurfaceRowsUncached(prefixFactors, factor, finiteVarName, finiteValues);
		}
		FiniteDerivedSurfaceCacheKey cacheKey = FiniteDerivedSurfaceCacheKey.of(prefixFactors, factor,
				finiteVarName, finiteValues);
		Optional<FiniteDerivedSurfaceEstimate> cachedEstimate = scope.finiteDerivedSurfaceCache.get(cacheKey);
		if (cachedEstimate != null) {
			scope.finiteDerivedSurfaceCacheHits++;
			return cachedEstimate.orElse(null);
		}
		scope.finiteDerivedSurfaceCacheMisses++;
		FiniteDerivedSurfaceEstimate estimate = finiteDerivedSurfaceRowsUncached(prefixFactors, factor,
				finiteVarName, finiteValues);
		scope.finiteDerivedSurfaceCache.put(cacheKey, Optional.ofNullable(estimate));
		return estimate;
	}

	private FiniteDerivedSurfaceEstimate finiteDerivedSurfaceRowsUncached(List<TupleExpr> prefixFactors,
			TupleExpr factor, String finiteVarName, Set<Value> finiteValues) {
		double rows = 0.0d;
		double prefixRows = 0.0d;
		int branchCount = 0;
		for (Value finiteValue : finiteValues) {
			List<TupleExpr> branchFactors = new ArrayList<>(prefixFactors.size() + 1);
			boolean substituted = false;
			for (TupleExpr prefixFactor : prefixFactors) {
				SubstitutedFactor substitutedFactor = substituteFiniteValue(prefixFactor, finiteVarName, finiteValue);
				if (substitutedFactor.unsupported()) {
					return null;
				}
				if (substitutedFactor.factor() == null) {
					continue;
				}
				substituted |= substitutedFactor.substituted();
				branchFactors.add(substitutedFactor.factor());
			}
			if (!substituted) {
				return null;
			}
			SubstitutedFactor currentFactor = substituteFiniteValue(factor, finiteVarName, finiteValue);
			if (currentFactor.unsupported() || currentFactor.factor() == null) {
				return null;
			}
			List<TupleExpr> branchWithCurrentFactor = new ArrayList<>(branchFactors.size() + 1);
			branchWithCurrentFactor.addAll(branchFactors);
			branchWithCurrentFactor.add(currentFactor.factor());

			Set<String> sharedBindingNames = sharedBindingNames(branchFactors, currentFactor.factor(), finiteVarName);
			if (sharedBindingNames.isEmpty()) {
				return null;
			}

			double branchRows = Double.NaN;
			double branchPrefixRows = Double.NaN;
			for (String sharedBindingName : sharedBindingNames) {
				double prefixSurfaceRows = finiteBranchSurfaceRows(branchFactors, sharedBindingName);
				if (isFiniteNonNegative(prefixSurfaceRows) && (!isFiniteNonNegative(branchPrefixRows)
						|| prefixSurfaceRows < branchPrefixRows)) {
					branchPrefixRows = prefixSurfaceRows;
				}
				double surfaceRows = finiteBranchSurfaceRows(branchFactors, currentFactor.factor(),
						sharedBindingName);
				if (isFiniteNonNegative(surfaceRows) && (!isFiniteNonNegative(branchRows)
						|| surfaceRows < branchRows)) {
					branchRows = surfaceRows;
				}
			}
			branchPrefixRows = smallerFiniteRowCount(branchPrefixRows, estimateFiniteBranchRows(branchFactors));
			branchRows = smallerFiniteRowCount(branchRows, estimateFiniteBranchRows(branchWithCurrentFactor));
			if (!isFiniteNonNegative(branchRows) || !isFiniteNonNegative(branchPrefixRows)) {
				return null;
			}
			rows += branchRows;
			prefixRows += branchPrefixRows;
			branchCount++;
			if (!isFiniteNonNegative(rows) || !isFiniteNonNegative(prefixRows)) {
				return null;
			}
		}
		return new FiniteDerivedSurfaceEstimate(rows, prefixRows, branchCount);
	}

	private double estimateFiniteBranchRows(List<TupleExpr> branchFactors) {
		if (branchFactors == null || branchFactors.isEmpty()) {
			return Double.NaN;
		}
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope == null) {
			return sketchBasedJoinEstimator.orderedCardinality(branchFactors);
		}
		FiniteBranchRowsCacheKey cacheKey = FiniteBranchRowsCacheKey.of(branchFactors);
		Double cachedRows = scope.finiteBranchRowsCache.get(cacheKey);
		if (cachedRows != null) {
			scope.finiteBranchRowsCacheHits++;
			return cachedRows;
		}
		scope.finiteBranchRowsCacheMisses++;
		double rows = sketchBasedJoinEstimator.orderedCardinality(branchFactors);
		scope.finiteBranchRowsCache.put(cacheKey, rows);
		return rows;
	}

	private double smallerFiniteRowCount(double currentRows, double candidateRows) {
		if (!isFiniteNonNegative(candidateRows)) {
			return currentRows;
		}
		if (!isFiniteNonNegative(currentRows)) {
			return candidateRows;
		}
		return Math.min(currentRows, candidateRows);
	}

	private double comparableBaseWorkRows(TupleExpr factor, JoinFactorCostModel.CostContext context,
			FactorCostEstimate baseEstimate) {
		if (context == null || baseEstimate == null || baseEstimate.isRepeatedInvocationsCosted()) {
			return baseEstimate == null ? Double.NaN : baseEstimate.getWorkRows();
		}
		double prefixRows = estimateFiniteBranchRows(context.getPrefixFactors());
		if (!context.isNestedIteratorInvocation()) {
			if (!isFiniteNonNegative(prefixRows) || prefixRows <= 1.0d) {
				prefixRows = context.getOuterPrefixRows();
			}
			if (!isFiniteNonNegative(prefixRows) || prefixRows <= 1.0d) {
				return baseEstimate.getWorkRows();
			}
			double distinctLookupBindings = context.getDistinctLookupBindings();
			if (!isFiniteNonNegative(distinctLookupBindings) || distinctLookupBindings <= 0.0d) {
				distinctLookupBindings = prefixRows;
			}
			JoinFactorCostModel.CostContext repeatedContext;
			if (context.hasCurrentlyBoundVarMask()) {
				repeatedContext = JoinFactorCostModel.CostContext.of(context.getVariableNames(),
						context.getCurrentlyBoundVarMask(), prefixRows, distinctLookupBindings, true,
						context.shouldCollectMetrics(), context.getFiniteBindingValues(), context.getPrefixFactors());
			} else {
				repeatedContext = JoinFactorCostModel.CostContext.of(context.getCurrentlyBoundVars(), prefixRows,
						distinctLookupBindings, true, context.shouldCollectMetrics(), context.getFiniteBindingValues(),
						context.getPrefixFactors());
			}
			FactorCostEstimate repeatedBaseEstimate = accountNestedInvocationWork(factor, baseEstimate,
					repeatedContext);
			return repeatedBaseEstimate == null ? baseEstimate.getWorkRows() : repeatedBaseEstimate.getWorkRows();
		}
		if (isFiniteNonNegative(prefixRows) && prefixRows > 1.0d) {
			double distinctLookupBindings = context.getDistinctLookupBindings();
			if (!isFiniteNonNegative(distinctLookupBindings) || distinctLookupBindings <= 0.0d) {
				distinctLookupBindings = prefixRows;
			}
			JoinFactorCostModel.CostContext repeatedContext;
			if (context.hasCurrentlyBoundVarMask()) {
				repeatedContext = JoinFactorCostModel.CostContext.of(context.getVariableNames(),
						context.getCurrentlyBoundVarMask(), prefixRows, distinctLookupBindings, true,
						context.shouldCollectMetrics(), context.getFiniteBindingValues(), context.getPrefixFactors());
			} else {
				repeatedContext = JoinFactorCostModel.CostContext.of(context.getCurrentlyBoundVars(), prefixRows,
						distinctLookupBindings, true, context.shouldCollectMetrics(), context.getFiniteBindingValues(),
						context.getPrefixFactors());
			}
			FactorCostEstimate repeatedBaseEstimate = accountNestedInvocationWork(factor, baseEstimate,
					repeatedContext);
			return repeatedBaseEstimate == null ? baseEstimate.getWorkRows() : repeatedBaseEstimate.getWorkRows();
		}
		FactorCostEstimate nestedBaseEstimate = accountNestedInvocationWork(factor, baseEstimate, context);
		return nestedBaseEstimate == null ? baseEstimate.getWorkRows() : nestedBaseEstimate.getWorkRows();
	}

	private double comparableBaseWorkRows(List<TupleExpr> prefixFactors, FactorCostEstimate baseEstimate) {
		if (baseEstimate == null || baseEstimate.isRepeatedInvocationsCosted()) {
			return baseEstimate == null ? Double.NaN : baseEstimate.getWorkRows();
		}
		double prefixRows = estimateFiniteBranchRows(prefixFactors);
		if (!isFiniteNonNegative(prefixRows) || prefixRows <= 1.0d) {
			return baseEstimate.getWorkRows();
		}
		double perInvocationWorkRows = baseEstimate.getWorkRows();
		if (isFiniteNonNegative(baseEstimate.getAccessRowsBeforeFilter())) {
			perInvocationWorkRows = Math.max(perInvocationWorkRows, baseEstimate.getAccessRowsBeforeFilter());
		}
		double repeatedInvocations = repeatedInvocations(baseEstimate, prefixRows, prefixRows);
		double workRows = repeatedInvocations * perInvocationWorkRows;
		return isFiniteNonNegative(workRows) ? Math.max(repeatedInvocations, workRows) : baseEstimate.getWorkRows();
	}

	private double comparableBaseOutputRows(JoinFactorCostModel.CostContext context,
			FactorCostEstimate baseEstimate) {
		if (context == null || baseEstimate == null || baseEstimate.isRepeatedInvocationsCosted()
				|| !isFiniteNonNegative(baseEstimate.getOutputRows())) {
			return baseEstimate == null ? Double.NaN : baseEstimate.getOutputRows();
		}
		double prefixRows = estimateFiniteBranchRows(context.getPrefixFactors());
		if (!isFiniteNonNegative(prefixRows) || prefixRows <= 1.0d) {
			prefixRows = context.getOuterPrefixRows();
		}
		if (!isFiniteNonNegative(prefixRows) || prefixRows <= 1.0d) {
			return baseEstimate.getOutputRows();
		}
		double distinctLookupBindings = context.getDistinctLookupBindings();
		double repeatedInvocations = repeatedInvocations(baseEstimate, prefixRows, distinctLookupBindings);
		double outputRows = baseEstimate.getOutputRows() * repeatedInvocations;
		return isFiniteNonNegative(outputRows) ? outputRows : baseEstimate.getOutputRows();
	}

	private double comparableBaseOutputRows(List<TupleExpr> prefixFactors, FactorCostEstimate baseEstimate) {
		if (baseEstimate == null || baseEstimate.isRepeatedInvocationsCosted()
				|| !isFiniteNonNegative(baseEstimate.getOutputRows())) {
			return baseEstimate == null ? Double.NaN : baseEstimate.getOutputRows();
		}
		double prefixRows = estimateFiniteBranchRows(prefixFactors);
		if (!isFiniteNonNegative(prefixRows) || prefixRows <= 1.0d) {
			return baseEstimate.getOutputRows();
		}
		double repeatedInvocations = repeatedInvocations(baseEstimate, prefixRows, prefixRows);
		double outputRows = baseEstimate.getOutputRows() * repeatedInvocations;
		return isFiniteNonNegative(outputRows) ? outputRows : baseEstimate.getOutputRows();
	}

	private boolean finiteDerivedEstimateIsWorse(FactorCostEstimate baseEstimate,
			AccessPathEstimate finiteDerivedEstimate, double finiteDerivedRows, double comparableBaseWorkRows,
			double comparableBaseOutputRows) {
		if (!baseEstimate.hasPhysicalAccessPath()) {
			return false;
		}
		boolean baseCompleteLookupAlreadyCoversFiniteAccess = baseEstimate.getMissingLookupComponentMask() == 0
				&& (baseEstimate.getLookupComponentMask()
						& finiteDerivedEstimate.lookupComponentMask()) == finiteDerivedEstimate.lookupComponentMask();
		if (baseCompleteLookupAlreadyCoversFiniteAccess && finiteDerivedEstimate.missingLookupComponentMask() != 0) {
			return true;
		}
		double baseAccessRows = baseEstimate.getAccessRowsBeforeFilter();
		double baseOutputRows = isFiniteNonNegative(comparableBaseOutputRows)
				? comparableBaseOutputRows
				: baseEstimate.getOutputRows();
		double baseWorkRows = comparableBaseWorkRows;
		if (isFiniteNonNegative(baseOutputRows)) {
			baseWorkRows = isFiniteNonNegative(baseWorkRows) ? Math.max(baseWorkRows, baseOutputRows) : baseOutputRows;
		}
		if (finiteDerivedEstimateDoesNotImproveSmallBase(finiteDerivedEstimate, finiteDerivedRows, baseWorkRows,
				baseOutputRows, baseAccessRows)) {
			return true;
		}
		if (baseCompleteLookupAlreadyCoversFiniteAccess
				&& !finiteDerivedEstimateMateriallyImprovesCompleteLookup(finiteDerivedEstimate, finiteDerivedRows,
						baseWorkRows, baseOutputRows, baseAccessRows)) {
			return true;
		}
		if (!baseEstimate.hasExactOutputRows()
				&& isMaterialFiniteDerivedCorrection(baseOutputRows, finiteDerivedRows)) {
			return false;
		}
		boolean workIsBetter = isFiniteNonNegative(baseWorkRows)
				&& finiteDerivedEstimate.workRowsPerInvocation() < baseWorkRows;
		boolean workIsWorse = isFiniteNonNegative(baseWorkRows)
				&& finiteDerivedEstimate.workRowsPerInvocation() > baseWorkRows;
		boolean accessIsWorse = isFiniteNonNegative(baseAccessRows)
				&& finiteDerivedEstimate.rowsBeforeFilterAtAccess() > baseAccessRows;
		boolean outputIsWorse = isFiniteNonNegative(baseOutputRows) && isFiniteNonNegative(finiteDerivedRows)
				&& finiteDerivedRows > baseOutputRows;
		if (baseEstimate.getMissingLookupComponentMask() != 0) {
			if (workIsBetter || isMaterialFiniteDerivedCorrection(baseOutputRows, finiteDerivedRows)) {
				return false;
			}
			return workIsWorse && accessIsWorse;
		}
		if (accessIsWorse && outputIsWorse && !workIsBetter) {
			return true;
		}
		if (!baseEstimate.isDirectLookup() && accessIsWorse && outputIsWorse) {
			return true;
		}
		return workIsWorse && (accessIsWorse || outputIsWorse);
	}

	private boolean finiteDerivedEstimateDoesNotImproveSmallBase(AccessPathEstimate finiteDerivedEstimate,
			double finiteDerivedRows, double baseWorkRows, double baseOutputRows, double baseAccessRows) {
		if (!isFiniteNonNegative(finiteDerivedRows)
				|| finiteDerivedRows >= FINITE_DERIVED_SURFACE_MIN_COMPLETE_LOOKUP_ROWS) {
			return false;
		}
		double smallSurfaceCeiling = finiteDerivedRows * FINITE_DERIVED_SURFACE_MIN_IMPROVEMENT_RATIO;
		if (isFiniteNonNegative(baseAccessRows) && baseAccessRows <= smallSurfaceCeiling) {
			return true;
		}
		if (isFiniteNonNegative(baseOutputRows) && baseOutputRows <= smallSurfaceCeiling) {
			return true;
		}
		return isFiniteNonNegative(baseWorkRows)
				&& baseWorkRows <= Math.max(smallSurfaceCeiling, finiteDerivedEstimate.workRowsPerInvocation());
	}

	private boolean finiteDerivedEstimateMateriallyImprovesCompleteLookup(AccessPathEstimate finiteDerivedEstimate,
			double finiteDerivedRows, double baseWorkRows, double baseOutputRows, double baseAccessRows) {
		double baseRows = isFiniteNonNegative(baseOutputRows) ? baseOutputRows : baseAccessRows;
		if (isFiniteNonNegative(baseRows)
				&& baseRows > 0.0d
				&& isFiniteNonNegative(finiteDerivedRows)
				&& baseRows >= finiteDerivedRows * FINITE_DERIVED_SURFACE_MIN_IMPROVEMENT_RATIO) {
			return true;
		}
		if (!isFiniteNonNegative(baseWorkRows) || baseWorkRows <= 0.0d
				|| !isFiniteNonNegative(finiteDerivedRows)
				|| finiteDerivedRows < FINITE_DERIVED_SURFACE_MIN_COMPLETE_LOOKUP_ROWS) {
			return false;
		}
		return finiteDerivedEstimate.workRowsPerInvocation() <= baseWorkRows;
	}

	private boolean isMaterialFiniteDerivedCorrection(double baseOutputRows, double finiteDerivedRows) {
		if (!isFiniteNonNegative(finiteDerivedRows)) {
			return false;
		}
		if (!isFiniteNonNegative(baseOutputRows) || baseOutputRows <= 0.0d) {
			return true;
		}
		double correctionFloor = Math.max(baseOutputRows * FINITE_DERIVED_SURFACE_MIN_CORRECTION_RATIO,
				FINITE_DERIVED_SURFACE_MIN_CORRECTION_RATIO);
		if (finiteDerivedRows >= correctionFloor) {
			return true;
		}
		double improvementFloor = Math.max(finiteDerivedRows * FINITE_DERIVED_SURFACE_MIN_IMPROVEMENT_RATIO,
				FINITE_DERIVED_SURFACE_MIN_IMPROVEMENT_RATIO);
		return baseOutputRows >= improvementFloor;
	}

	private double finiteBranchSurfaceRows(List<TupleExpr> factors, String joinVarName) {
		countSketchJoinSurfaceCall();
		double rows = sketchBasedJoinEstimator.estimateSketchJoinSurfaceRows(factors, joinVarName);
		if (isPositiveFinite(rows)) {
			return rows;
		}

		countExactJoinSurfaceCall();
		rows = sketchBasedJoinEstimator.estimateExactJoinSurfaceRows(factors, joinVarName);
		if (isFiniteNonNegative(rows)) {
			return rows;
		}

		countFallbackJoinSurfaceCall();
		return sketchBasedJoinEstimator.estimateJoinSurfaceRows(factors, joinVarName);
	}

	private double finiteBranchSurfaceRows(List<TupleExpr> prefixFactors, TupleExpr factor, String joinVarName) {
		countSketchJoinSurfaceCall();
		double rows = sketchBasedJoinEstimator.estimateSketchJoinSurfaceRows(prefixFactors, factor, joinVarName);
		if (isPositiveFinite(rows)) {
			return rows;
		}

		countExactJoinSurfaceCall();
		rows = sketchBasedJoinEstimator.estimateExactJoinSurfaceRows(prefixFactors, factor, joinVarName);
		if (isFiniteNonNegative(rows)) {
			return rows;
		}
		countFallbackJoinSurfaceCall();
		return sketchBasedJoinEstimator.estimateJoinSurfaceRows(prefixFactors, factor, joinVarName);
	}

	private void countExactJoinSurfaceCall() {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope != null) {
			scope.exactJoinSurfaceCalls++;
		}
	}

	private void countSketchJoinSurfaceCall() {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope != null) {
			scope.sketchJoinSurfaceCalls++;
		}
	}

	private void countFallbackJoinSurfaceCall() {
		OptimizationCostScope scope = optimizationCostScope.get();
		if (scope != null) {
			scope.fallbackJoinSurfaceCalls++;
		}
	}

	private boolean isPositiveFinite(double rows) {
		return isFiniteNonNegative(rows) && rows > 0.0d;
	}

	private Set<String> sharedBindingNames(List<TupleExpr> prefixFactors, TupleExpr factor,
			String excludedBindingName) {
		Set<String> seen = new HashSet<>();
		for (TupleExpr prefixFactor : prefixFactors) {
			seen.addAll(prefixFactor.getBindingNames());
		}

		Set<String> shared = new HashSet<>();
		for (String bindingName : factor.getBindingNames()) {
			if (!bindingName.equals(excludedBindingName) && seen.contains(bindingName)) {
				shared.add(bindingName);
			}
		}
		return shared;
	}

	private boolean sharesBindingName(List<TupleExpr> branchFactors) {
		if (branchFactors.size() < 2) {
			return false;
		}
		Set<String> seen = new HashSet<>();
		for (TupleExpr branchFactor : branchFactors) {
			for (String bindingName : branchFactor.getBindingNames()) {
				if (seen.contains(bindingName)) {
					return true;
				}
			}
			seen.addAll(branchFactor.getBindingNames());
		}
		return false;
	}

	private SubstitutedFactor substituteFiniteValue(TupleExpr tupleExpr, String finiteVarName, Value finiteValue) {
		if (tupleExpr instanceof BindingSetAssignment) {
			return SubstitutedFactor.skipped();
		}
		if (!(tupleExpr instanceof StatementPattern pattern)) {
			return SubstitutedFactor.unsupportedFactor();
		}
		StatementPattern clone = pattern.clone();
		boolean substituted = substituteFiniteValue(clone, clone.getSubjectVar(), finiteVarName, finiteValue);
		substituted |= substituteFiniteValue(clone, clone.getPredicateVar(), finiteVarName, finiteValue);
		substituted |= substituteFiniteValue(clone, clone.getObjectVar(), finiteVarName, finiteValue);
		substituted |= substituteFiniteValue(clone, clone.getContextVar(), finiteVarName, finiteValue);
		return new SubstitutedFactor(clone, substituted, false);
	}

	private boolean substituteFiniteValue(StatementPattern pattern, Var var, String finiteVarName, Value finiteValue) {
		if (var == null || var.hasValue() || !finiteVarName.equals(var.getName())) {
			return false;
		}
		pattern.replaceChildNode(var, Var.of(var.getName(), finiteValue, var.isAnonymous(), var.isConstant()));
		return true;
	}

	private Optional<FactorCostEstimate> estimateFiniteBindingLookupCost(TupleExpr factor,
			SketchBasedJoinEstimator.AccessShape accessShape, double outputRows,
			Map<String, Set<Value>> finiteBindingValues, boolean collectMetrics) {
		if (accessShape == null || !hasFiniteBindingValues(finiteBindingValues)) {
			return Optional.empty();
		}
		StatementPattern pattern = accessShape.pattern();
		if (pattern == null) {
			return Optional.empty();
		}
		int lookupComponentMask = finiteLookupComponentMask(accessShape, pattern, finiteBindingValues);
		if (lookupComponentMask == 0) {
			return Optional.empty();
		}

		long[][] idsByComponent = new long[Component.values().length][];
		int finiteLookupComponentMask = 0;
		int lookupCombinations = 1;
		boolean hasFiniteJoinComponent = false;

		for (Component component : Component.values()) {
			int componentMask = componentBit(component);
			if ((lookupComponentMask & componentMask) == 0) {
				continue;
			}
			Var componentVar = componentVar(pattern, component);
			if (componentVar != null && componentVar.hasValue()) {
				long id = lookupId(component, componentVar.getValue());
				idsByComponent[component.ordinal()] = id == Long.MIN_VALUE ? new long[0] : new long[] { id };
				finiteLookupComponentMask |= componentMask;
				continue;
			}
			String varName = accessShape.joinBoundVarName(component);
			if (varName == null && componentVar != null) {
				varName = componentVar.getName();
			}
			if (varName == null) {
				return Optional.empty();
			}
			Set<Value> values = finiteBindingValues.get(varName);
			if (values == null || values.isEmpty()) {
				return Optional.empty();
			}
			long[] ids = lookupIds(component, values);
			idsByComponent[component.ordinal()] = ids;
			finiteLookupComponentMask |= componentMask;
			hasFiniteJoinComponent = true;
			lookupCombinations *= Math.max(1, values.size());
			if (lookupCombinations > FINITE_LOOKUP_MAX_COMBINATIONS) {
				return Optional.empty();
			}
		}

		if (!hasFiniteJoinComponent) {
			return Optional.empty();
		}

		double accessRows = finiteLookupRows(idsByComponent, 0, LmdbValue.UNKNOWN_ID, LmdbValue.UNKNOWN_ID,
				LmdbValue.UNKNOWN_ID, LmdbValue.UNKNOWN_ID);
		if (!isFiniteNonNegative(accessRows)) {
			return Optional.empty();
		}
		double finiteFilterMultiplier = finiteBindingFilterMultiplier(factor, finiteBindingValues);
		double filterMultiplier = isFiniteNonNegative(finiteFilterMultiplier)
				? finiteFilterMultiplier
				: accessShape.filterMultiplier();
		double rowsAfterFilter = accessRows;
		if (isFiniteNonNegative(filterMultiplier) && filterMultiplier < 1.0d) {
			rowsAfterFilter *= filterMultiplier;
		}
		if (!isFiniteNonNegative(rowsAfterFilter)) {
			return Optional.empty();
		}

		AccessPathEstimate accessPathEstimate = chooseFiniteAccessPath(finiteLookupComponentMask, accessRows,
				rowsAfterFilter, lookupCombinations);
		if (accessPathEstimate == null) {
			return Optional.empty();
		}
		Map<String, String> stringMetrics = new HashMap<>();
		Map<String, Double> doubleMetrics = new HashMap<>();
		stringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_NAME, accessPathEstimate.indexFieldSequence());
		stringMetrics.put(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS,
				componentMaskString(accessPathEstimate.lookupComponentMask()));
		stringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, accessMode(accessPathEstimate));
		stringMetrics.put(TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, "lmdb-finite-binding-lookup");
		if (isFiniteNonNegative(finiteFilterMultiplier)) {
			stringMetrics.put(TelemetryMetricNames.FILTER_SELECTIVITY_SOURCE, "finite_binding");
		}
		if (accessPathEstimate.missingLookupComponentMask() != 0) {
			stringMetrics.put(TelemetryMetricNames.PLANNED_MISSING_LOOKUP_COMPONENTS,
					componentMaskString(accessPathEstimate.missingLookupComponentMask()));
		}
		doubleMetrics.put(TelemetryMetricNames.PLANNED_INDEX_PREFIX_LENGTH,
				(double) accessPathEstimate.prefixLength());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS, accessPathEstimate.rowsBeforeFilterAtAccess());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, accessPathEstimate.workRowsPerInvocation());
		doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_PATH_CANDIDATES,
				(double) accessPathEstimate.candidateCount());
		doubleMetrics.put("plannedRepeatedInvocations", (double) lookupCombinations);
		if (isFiniteNonNegative(finiteFilterMultiplier)) {
			doubleMetrics.put(TelemetryMetricNames.PLANNED_FILTER_PASS_RATIO, finiteFilterMultiplier);
		}
		if (accessPathEstimate.rowsAfterFilterAtAccess() != accessPathEstimate.rowsBeforeFilterAtAccess()) {
			doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS_AFTER_FILTER,
					accessPathEstimate.rowsAfterFilterAtAccess());
		}
		double factorRows = rowsAfterFilter;
		return Optional.of(new FactorCostEstimate(accessPathEstimate.workRowsPerInvocation(), factorRows,
				stringMetrics, doubleMetrics, true, accessPathEstimate.directLookup(),
				accessPathEstimate.lookupComponentMask(), accessPathEstimate.missingLookupComponentMask(),
				accessPathEstimate.rowsBeforeFilterAtAccess(), true, true));
	}

	private double finiteBindingFilterMultiplier(TupleExpr factor, Map<String, Set<Value>> finiteBindingValues) {
		if (!(factor instanceof Filter filter) || filter.getCondition() == null
				|| !hasFiniteBindingValues(finiteBindingValues)) {
			return Double.NaN;
		}

		List<String> variableNames = new ArrayList<>();
		if (!collectFiniteFilterVariables(filter.getCondition(), finiteBindingValues, variableNames, new HashSet<>())
				|| variableNames.isEmpty()) {
			return Double.NaN;
		}

		int combinations = 1;
		for (String variableName : variableNames) {
			Set<Value> values = finiteBindingValues.get(variableName);
			if (values == null || values.isEmpty()) {
				return Double.NaN;
			}
			combinations *= values.size();
			if (combinations > FINITE_LOOKUP_MAX_COMBINATIONS) {
				return Double.NaN;
			}
		}

		FiniteFilterCounter counter = new FiniteFilterCounter();
		countFiniteFilterMatches(filter.getCondition(), finiteBindingValues, variableNames, 0, new LinkedHashMap<>(),
				counter);
		if (counter.total == 0) {
			return Double.NaN;
		}
		return (double) counter.matched / counter.total;
	}

	private boolean collectFiniteFilterVariables(ValueExpr condition, Map<String, Set<Value>> finiteBindingValues,
			List<String> variableNames, Set<String> seen) {
		if (condition instanceof Var var) {
			if (var.hasValue()) {
				return true;
			}
			String name = var.getName();
			if (name == null) {
				return false;
			}
			Set<Value> values = finiteBindingValues.get(name);
			if (values == null || values.isEmpty()) {
				return false;
			}
			if (seen.add(name)) {
				variableNames.add(name);
			}
			return true;
		}
		if (condition instanceof ValueConstant) {
			return true;
		}
		if (condition instanceof And and) {
			return collectFiniteFilterVariables(and.getLeftArg(), finiteBindingValues, variableNames, seen)
					&& collectFiniteFilterVariables(and.getRightArg(), finiteBindingValues, variableNames, seen);
		}
		if (condition instanceof Compare compare) {
			return collectFiniteFilterVariables(compare.getLeftArg(), finiteBindingValues, variableNames, seen)
					&& collectFiniteFilterVariables(compare.getRightArg(), finiteBindingValues, variableNames, seen);
		}
		if (condition instanceof ListMemberOperator listMemberOperator) {
			for (ValueExpr argument : listMemberOperator.getArguments()) {
				if (!collectFiniteFilterVariables(argument, finiteBindingValues, variableNames, seen)) {
					return false;
				}
			}
			return true;
		}
		return false;
	}

	private void countFiniteFilterMatches(ValueExpr condition, Map<String, Set<Value>> finiteBindingValues,
			List<String> variableNames, int index, Map<String, Value> bindings, FiniteFilterCounter counter) {
		if (index == variableNames.size()) {
			Boolean matched = evaluateFiniteFilterCondition(condition, bindings);
			if (matched != null) {
				counter.total++;
				if (matched) {
					counter.matched++;
				}
			}
			return;
		}

		String variableName = variableNames.get(index);
		Set<Value> values = finiteBindingValues.get(variableName);
		if (values == null || values.isEmpty()) {
			return;
		}
		for (Value value : values) {
			bindings.put(variableName, value);
			countFiniteFilterMatches(condition, finiteBindingValues, variableNames, index + 1, bindings, counter);
		}
		bindings.remove(variableName);
	}

	private Boolean evaluateFiniteFilterCondition(ValueExpr condition, Map<String, Value> bindings) {
		if (condition instanceof And and) {
			Boolean left = evaluateFiniteFilterCondition(and.getLeftArg(), bindings);
			if (left == null || !left) {
				return left;
			}
			return evaluateFiniteFilterCondition(and.getRightArg(), bindings);
		}
		if (condition instanceof Compare compare) {
			Value left = evaluateFiniteFilterValue(compare.getLeftArg(), bindings);
			Value right = evaluateFiniteFilterValue(compare.getRightArg(), bindings);
			if (left == null || right == null) {
				return null;
			}
			try {
				return QueryEvaluationUtil.compare(left, right, compare.getOperator(), false);
			} catch (ValueExprEvaluationException e) {
				return false;
			}
		}
		if (condition instanceof ListMemberOperator listMemberOperator) {
			List<ValueExpr> arguments = listMemberOperator.getArguments();
			if (arguments == null || arguments.size() < 2) {
				return null;
			}
			Value left = evaluateFiniteFilterValue(arguments.getFirst(), bindings);
			if (left == null) {
				return null;
			}
			for (int i = 1; i < arguments.size(); i++) {
				Value right = evaluateFiniteFilterValue(arguments.get(i), bindings);
				if (right == null) {
					return null;
				}
				if (finiteValuesEqual(left, right)) {
					return true;
				}
			}
			return false;
		}
		return null;
	}

	private Value evaluateFiniteFilterValue(ValueExpr expression, Map<String, Value> bindings) {
		if (expression instanceof Var var) {
			if (var.hasValue()) {
				return var.getValue();
			}
			return var.getName() == null ? null : bindings.get(var.getName());
		}
		if (expression instanceof ValueConstant valueConstant) {
			return valueConstant.getValue();
		}
		return null;
	}

	private boolean finiteValuesEqual(Value left, Value right) {
		try {
			return QueryEvaluationUtil.compare(left, right, Compare.CompareOp.EQ, false);
		} catch (ValueExprEvaluationException e) {
			return left.equals(right);
		}
	}

	private static final class FiniteFilterCounter {
		private int total;
		private int matched;
	}

	private int finiteLookupComponentMask(SketchBasedJoinEstimator.AccessShape accessShape, StatementPattern pattern,
			Map<String, Set<Value>> finiteBindingValues) {
		int lookupComponentMask = accessShape.lookupBoundComponentMask();
		boolean hasFinitePatternComponent = false;
		for (Component component : Component.values()) {
			Var componentVar = componentVar(pattern, component);
			if (componentVar == null) {
				continue;
			}
			int componentMask = componentBit(component);
			if (componentVar.hasValue()) {
				lookupComponentMask |= componentMask;
				continue;
			}
			String varName = componentVar.getName();
			Set<Value> values = varName == null ? null : finiteBindingValues.get(varName);
			if (values != null && !values.isEmpty()) {
				lookupComponentMask |= componentMask;
				hasFinitePatternComponent = true;
			}
		}
		return hasFinitePatternComponent ? lookupComponentMask : accessShape.lookupBoundComponentMask();
	}

	private long[] lookupIds(Component component, Set<Value> values) {
		long[] ids = new long[values.size()];
		int count = 0;
		for (Value value : values) {
			long id = lookupId(component, value);
			if (id != Long.MIN_VALUE) {
				ids[count++] = id;
			}
		}
		if (count == ids.length) {
			return ids;
		}
		long[] filtered = new long[count];
		System.arraycopy(ids, 0, filtered, 0, count);
		return filtered;
	}

	private long lookupId(Component component, Value value) {
		if (value == null || !isValidLookupValue(component, value)) {
			return Long.MIN_VALUE;
		}
		try {
			long id = valueStore.getId(value);
			return id == LmdbValue.UNKNOWN_ID ? Long.MIN_VALUE : id;
		} catch (IOException | RuntimeException e) {
			return Long.MIN_VALUE;
		}
	}

	private boolean isValidLookupValue(Component component, Value value) {
		return switch (component) {
		case S, C -> value instanceof Resource;
		case P -> value instanceof IRI;
		case O -> true;
		};
	}

	private double finiteLookupRows(long[][] idsByComponent, int componentIndex, long subj, long pred, long obj,
			long context) {
		if (componentIndex >= Component.values().length) {
			return statementPatternCardinalitySource.estimateIds(subj, pred, obj, context);
		}
		long[] ids = idsByComponent[componentIndex];
		if (ids == null) {
			return finiteLookupRows(idsByComponent, componentIndex + 1, subj, pred, obj, context);
		}
		if (ids.length == 0) {
			return 0.0d;
		}
		Component component = Component.values()[componentIndex];
		double rows = 0.0d;
		for (long id : ids) {
			double componentRows = switch (component) {
			case S -> finiteLookupRows(idsByComponent, componentIndex + 1, id, pred, obj, context);
			case P -> finiteLookupRows(idsByComponent, componentIndex + 1, subj, id, obj, context);
			case O -> finiteLookupRows(idsByComponent, componentIndex + 1, subj, pred, id, context);
			case C -> finiteLookupRows(idsByComponent, componentIndex + 1, subj, pred, obj, id);
			};
			if (!isFiniteNonNegative(componentRows)) {
				return Double.NaN;
			}
			rows += componentRows;
			if (!isFiniteNonNegative(rows)) {
				return Double.NaN;
			}
		}
		return rows;
	}

	private AccessPathEstimate chooseFiniteAccessPath(int lookupComponentMask, double rowsBeforeFilter,
			double rowsAfterFilter, int lookupCombinations) {
		AccessPathEstimate bestEstimate = null;
		List<TripleStore.IndexAccessPath> candidates = tripleStore.indexAccessPaths(lookupComponentMask);
		int candidateCount = candidates.size();
		for (TripleStore.IndexAccessPath candidate : candidates) {
			int coveredLookupComponentMask = lookupComponentMask & candidate.prefixComponentMask();
			boolean directLookup = (candidate.prefixComponentMask() & lookupComponentMask) == lookupComponentMask;
			double workRows = directLookup
					? Math.max(lookupCombinations, rowsAfterFilter)
					: rowsBeforeFilter;
			if (!isFiniteNonNegative(workRows)) {
				continue;
			}
			AccessPathEstimate estimate = new AccessPathEstimate(workRows, rowsBeforeFilter, rowsAfterFilter,
					candidate.indexFieldSequence(), candidate.prefixLength(), candidate.prefixComponentMask(),
					directLookup, coveredLookupComponentMask,
					lookupComponentMask & ~candidate.prefixComponentMask(), candidateCount);
			if (bestEstimate == null || compareAccessPathEstimate(estimate, bestEstimate) < 0) {
				bestEstimate = estimate;
			}
		}
		return bestEstimate;
	}

	private Var componentVar(StatementPattern pattern, Component component) {
		return switch (component) {
		case S -> pattern.getSubjectVar();
		case P -> pattern.getPredicateVar();
		case O -> pattern.getObjectVar();
		case C -> pattern.getContextVar();
		};
	}

	private Optional<FactorCostEstimate> estimateLmdbFactorCost(double outputRows,
			SketchBasedJoinEstimator.AccessShape accessShape, boolean collectMetrics) {
		if (accessShape == null) {
			return Optional.of(new FactorCostEstimate(outputRows, outputRows));
		}

		AccessPathEstimate accessPathEstimate = chooseAccessPath(accessShape, outputRows);
		int prefixLength = accessPathEstimate == null ? 0 : accessPathEstimate.prefixLength();
		int lookupComponentMask = accessPathEstimate == null ? accessShape.lookupBoundComponentMask()
				: accessPathEstimate.lookupComponentMask();
		String indexAccessMode = accessMode(accessPathEstimate);
		int missingLookupComponentMask = accessPathEstimate == null ? accessShape.lookupBoundComponentMask()
				: accessPathEstimate.missingLookupComponentMask();
		Map<String, String> stringMetrics = Map.of();
		Map<String, Double> doubleMetrics = Map.of();
		if (collectMetrics) {
			Map<String, String> mutableStringMetrics = new HashMap<>();
			Map<String, Double> mutableDoubleMetrics = new HashMap<>();
			if (accessPathEstimate != null && prefixLength > 0) {
				mutableStringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_NAME,
						accessPathEstimate.indexFieldSequence());
				mutableDoubleMetrics.put(TelemetryMetricNames.PLANNED_INDEX_PREFIX_LENGTH, (double) prefixLength);
			}
			mutableStringMetrics.put(TelemetryMetricNames.PLANNED_LOOKUP_COMPONENTS,
					componentMaskString(lookupComponentMask));
			mutableStringMetrics.put(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, indexAccessMode);
			if (missingLookupComponentMask != 0) {
				mutableStringMetrics.put(TelemetryMetricNames.PLANNED_MISSING_LOOKUP_COMPONENTS,
						componentMaskString(missingLookupComponentMask));
			}
			stringMetrics = mutableStringMetrics;
			doubleMetrics = mutableDoubleMetrics;
		}
		if (accessPathEstimate != null) {
			if (collectMetrics) {
				doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS,
						accessPathEstimate.rowsBeforeFilterAtAccess());
				doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_PATH_CANDIDATES,
						(double) accessPathEstimate.candidateCount());
				if (isFiniteNonNegative(accessPathEstimate.rowsAfterFilterAtAccess())
						&& accessPathEstimate.rowsAfterFilterAtAccess() != accessPathEstimate
								.rowsBeforeFilterAtAccess()) {
					doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_ROWS_AFTER_FILTER,
							accessPathEstimate.rowsAfterFilterAtAccess());
				}
			}
		}

		double workRows = accessPathEstimate == null ? outputRows : accessPathEstimate.workRowsPerInvocation();
		double accessRowsBeforeFilter = accessPathEstimate == null ? Double.NaN
				: accessPathEstimate.rowsBeforeFilterAtAccess();
		if (collectMetrics) {
			doubleMetrics.put(TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, workRows);
		}
		return Optional.of(new FactorCostEstimate(workRows, outputRows, stringMetrics, doubleMetrics,
				true, "directLookup".equals(indexAccessMode), lookupComponentMask,
				missingLookupComponentMask, accessRowsBeforeFilter));
	}

	private Optional<FactorCostEstimate> estimateJoinFactorCost(Join join, Set<String> boundVars) {
		List<TupleExpr> flattenedFactors = new ArrayList<>();
		flattenJoinFactors(join, flattenedFactors);
		if (flattenedFactors.size() > 1 && supportsJoinEstimation()) {
			Optional<JoinOrderPlan> plan = estimateJoinOrder(flattenedFactors, boundVars, Algorithm.DYNAMIC_PROGRAMMING,
					List.of());
			if (plan.isPresent() && isFiniteNonNegative(plan.get().getEstimatedTotalWork())) {
				double outputRows = plan.get().getEstimatedFinalRows();
				if (!isFiniteNonNegative(outputRows)) {
					outputRows = estimateFactorOutputRows(join, boundVars);
				}
				if (isFiniteNonNegative(outputRows)) {
					return Optional.of(new FactorCostEstimate(plan.get().getEstimatedTotalWork(), outputRows));
				}
			}
		}
		Optional<FactorCostEstimate> leftEstimate = estimateLmdbFactorCost(join.getLeftArg(), boundVars);
		Set<String> rightBoundVars = unionBindingNames(boundVars, join.getLeftArg().getBindingNames());
		Optional<FactorCostEstimate> rightEstimate = estimateLmdbFactorCost(join.getRightArg(), rightBoundVars);
		if (leftEstimate.isEmpty() || rightEstimate.isEmpty()
				|| !isFiniteNonNegative(leftEstimate.get().getWorkRows())
				|| !isFiniteNonNegative(rightEstimate.get().getWorkRows())) {
			return Optional.empty();
		}

		double outputRows = estimateFactorOutputRows(join, boundVars);
		if (!isFiniteNonNegative(outputRows)) {
			outputRows = Math.max(leftEstimate.get().getOutputRows(), rightEstimate.get().getOutputRows());
		}
		double leftWorkRows = leftEstimate.get().getWorkRows();
		double leftOutputRows = leftEstimate.get().getOutputRows();
		double rightWorkRows = rightEstimate.get().getWorkRows();
		double repeatedRightWorkRows = leftWorkRows + Math.max(1.0d, leftOutputRows) * rightWorkRows;
		if (!isFiniteNonNegative(repeatedRightWorkRows)) {
			repeatedRightWorkRows = Double.MAX_VALUE;
		}
		return Optional.of(new FactorCostEstimate(repeatedRightWorkRows, outputRows));
	}

	private void flattenJoinFactors(TupleExpr tupleExpr, List<TupleExpr> factors) {
		if (tupleExpr instanceof Join join && !TupleExprs.isVariableScopeChange(tupleExpr)) {
			flattenJoinFactors(join.getLeftArg(), factors);
			flattenJoinFactors(join.getRightArg(), factors);
			return;
		}
		factors.add(tupleExpr);
	}

	private Set<String> unionBindingNames(Set<String> base, Set<String> additions) {
		if (base == null || base.isEmpty()) {
			return additions == null ? Set.of() : additions;
		}
		if (additions == null || additions.isEmpty()) {
			return base;
		}
		return new UnionBindingNameSet(base, additions);
	}

	private Map<String, Set<Value>> finiteBindingValuesForStep(Map<String, Set<Value>> finiteBindingValues,
			Set<String> boundVarsBefore) {
		if (finiteBindingValues.isEmpty() || boundVarsBefore == null || boundVarsBefore.isEmpty()) {
			return Map.of();
		}
		Map<String, Set<Value>> values = new HashMap<>();
		for (String name : boundVarsBefore) {
			Set<Value> finiteValues = finiteBindingValues.get(name);
			if (finiteValues != null && !finiteValues.isEmpty()) {
				values.put(name, finiteValues);
			}
		}
		return values.isEmpty() ? Map.of() : Map.copyOf(values);
	}

	private void addFiniteBindingValues(Map<String, Set<Value>> finiteBindingValues, TupleExpr tupleExpr) {
		if (tupleExpr == null) {
			return;
		}
		if (tupleExpr instanceof BindingSetAssignment assignment) {
			addFiniteBindingValues(finiteBindingValues, assignment);
			return;
		}
		if (tupleExpr instanceof Filter filter) {
			addFiniteBindingValues(finiteBindingValues, filter.getArg());
			return;
		}
		if (tupleExpr instanceof Join join && !TupleExprs.isVariableScopeChange(join)) {
			addFiniteBindingValues(finiteBindingValues, join.getLeftArg());
			addFiniteBindingValues(finiteBindingValues, join.getRightArg());
		}
	}

	private void addFiniteBindingValues(Map<String, Set<Value>> finiteBindingValues,
			BindingSetAssignment assignment) {
		Map<String, Set<Value>> assignmentValues = new HashMap<>();
		for (BindingSet bindingSet : assignment.getBindingSets()) {
			for (String bindingName : bindingSet.getBindingNames()) {
				Value value = bindingSet.getValue(bindingName);
				if (value != null) {
					assignmentValues.computeIfAbsent(bindingName, ignored -> new HashSet<>()).add(value);
				}
			}
		}
		for (Map.Entry<String, Set<Value>> entry : assignmentValues.entrySet()) {
			finiteBindingValues.merge(entry.getKey(), Set.copyOf(entry.getValue()), (left, right) -> {
				Set<Value> intersection = new HashSet<>(left);
				intersection.retainAll(right);
				return intersection.isEmpty() ? Set.of() : Set.copyOf(intersection);
			});
		}
	}

	private static final class UnionBindingNameSet extends AbstractSet<String> {
		private final Set<String> left;
		private final Set<String> right;
		private final int size;

		private UnionBindingNameSet(Set<String> left, Set<String> right) {
			this.left = left;
			this.right = right;
			int computedSize = left.size();
			for (String bindingName : right) {
				if (!left.contains(bindingName)) {
					computedSize++;
				}
			}
			this.size = computedSize;
		}

		@Override
		public Iterator<String> iterator() {
			Iterator<String> leftIterator = left.iterator();
			Iterator<String> rightIterator = right.iterator();
			return new Iterator<>() {
				private String nextRight;

				@Override
				public boolean hasNext() {
					if (leftIterator.hasNext()) {
						return true;
					}
					if (nextRight != null) {
						return true;
					}
					while (rightIterator.hasNext()) {
						String candidate = rightIterator.next();
						if (!left.contains(candidate)) {
							nextRight = candidate;
							return true;
						}
					}
					return false;
				}

				@Override
				public String next() {
					if (leftIterator.hasNext()) {
						return leftIterator.next();
					}
					if (nextRight != null || hasNext()) {
						String result = nextRight;
						nextRight = null;
						return result;
					}
					throw new java.util.NoSuchElementException();
				}
			};
		}

		@Override
		public boolean contains(Object value) {
			return left.contains(value) || right.contains(value);
		}

		@Override
		public int size() {
			return size;
		}
	}

	private String accessMode(AccessPathEstimate accessPathEstimate) {
		if (accessPathEstimate == null || accessPathEstimate.prefixLength() <= 0) {
			return "fullScan";
		}
		return accessPathEstimate.directLookup() ? "directLookup" : "prefixScan";
	}

	private double estimateFactorOutputRows(TupleExpr factor, Set<String> boundVars) {
		if (sketchBasedJoinEstimator != null) {
			double sketchRows = sketchBasedJoinEstimator.factorOutputRowsForJoinOrdering(factor, boundVars);
			if (isFiniteNonNegative(sketchRows)) {
				return sketchRows;
			}
		}
		if (factor instanceof BindingSetAssignment assignment) {
			double rows = 0.0d;
			for (Object ignored : assignment.getBindingSets()) {
				rows += 1.0d;
			}
			return rows;
		}
		return getCardinality(factor);
	}

	private double estimateFactorOutputRows(TupleExpr factor, String[] variableNames, long boundVarMask) {
		if (sketchBasedJoinEstimator != null) {
			double sketchRows = sketchBasedJoinEstimator.factorOutputRowsForJoinOrdering(factor, variableNames,
					boundVarMask);
			if (isFiniteNonNegative(sketchRows)) {
				return sketchRows;
			}
		}
		if (factor instanceof BindingSetAssignment assignment) {
			double rows = 0.0d;
			for (Object ignored : assignment.getBindingSets()) {
				rows += 1.0d;
			}
			return rows;
		}
		return getCardinality(factor);
	}

	private Set<String> boundVariableMaskSet(String[] variableNames, long boundVarMask) {
		if (variableNames == null || boundVarMask == 0L) {
			return Set.of();
		}
		return new BoundVariableMaskSet(variableNames, boundVarMask);
	}

	private static final class BoundVariableMaskSet extends AbstractSet<String> {
		private final String[] variableNames;
		private final long mask;

		private BoundVariableMaskSet(String[] variableNames, long mask) {
			this.variableNames = variableNames;
			this.mask = mask;
		}

		@Override
		public Iterator<String> iterator() {
			return new Iterator<>() {
				private long remaining = mask;

				@Override
				public boolean hasNext() {
					return remaining != 0L;
				}

				@Override
				public String next() {
					while (remaining != 0L) {
						int id = Long.numberOfTrailingZeros(remaining);
						remaining &= ~(1L << id);
						if (id >= 0 && id < variableNames.length && variableNames[id] != null) {
							return variableNames[id];
						}
					}
					throw new java.util.NoSuchElementException();
				}
			};
		}

		@Override
		public boolean contains(Object value) {
			if (!(value instanceof String)) {
				return false;
			}
			long remaining = mask;
			while (remaining != 0L) {
				int id = Long.numberOfTrailingZeros(remaining);
				remaining &= ~(1L << id);
				if (id >= 0 && id < variableNames.length && value.equals(variableNames[id])) {
					return true;
				}
			}
			return false;
		}

		@Override
		public int size() {
			return Long.bitCount(mask);
		}
	}

	private int accessLookupComponentMask(SketchBasedJoinEstimator.AccessShape accessShape) {
		return accessShape.lookupBoundComponentMask() & ~accessShape.filterLookupComponentMask();
	}

	private boolean canApplyFilterAtAccess(SketchBasedJoinEstimator.AccessShape accessShape,
			int prefixComponentMask) {
		int filterLookupComponentMask = accessShape.filterLookupComponentMask();
		if (filterLookupComponentMask == 0) {
			return false;
		}
		int accessLookupComponentMask = accessLookupComponentMask(accessShape);
		return (prefixComponentMask & accessLookupComponentMask) == accessLookupComponentMask
				&& (prefixComponentMask & filterLookupComponentMask) == filterLookupComponentMask;
	}

	private String componentMaskString(int componentMask) {
		if (componentMask == 0) {
			return "[]";
		}
		StringBuilder builder = new StringBuilder("[");
		boolean first = true;
		for (Component component : Component.values()) {
			if ((componentMask & (1 << component.ordinal())) == 0) {
				continue;
			}
			if (!first) {
				builder.append(", ");
			}
			builder.append(component);
			first = false;
		}
		return builder.append(']').toString();
	}

	private boolean isFiniteNonNegative(double value) {
		return Double.isFinite(value) && value >= 0.0d;
	}

	private AccessPathEstimate chooseAccessPath(SketchBasedJoinEstimator.AccessShape accessShape,
			double factorRows) {
		AccessPathEstimate bestEstimate = null;
		int lookupComponentMask = lookupComponentMaskWithConstants(accessShape, accessShape.pattern());
		List<TripleStore.IndexAccessPath> candidates = tripleStore.indexAccessPaths(lookupComponentMask);
		int candidateCount = candidates.size();
		for (TripleStore.IndexAccessPath candidate : candidates) {
			double rowsBefore = accessShape.estimateAccessRows(candidate.prefixComponentMask());
			if (!isFiniteNonNegative(rowsBefore)) {
				continue;
			}
			int coveredLookupComponentMask = lookupComponentMask & candidate.prefixComponentMask();
			int missingLookupComponentMask = lookupComponentMask & ~candidate.prefixComponentMask();
			if (missingLookupComponentMask != 0) {
				double rowsBeforeLowerBound = rowsBeforeFilterLowerBound(factorRows, accessShape.filterMultiplier());
				if (isFiniteNonNegative(rowsBeforeLowerBound) && rowsBeforeLowerBound > rowsBefore) {
					rowsBefore = rowsBeforeLowerBound;
				}
			}
			boolean filterAppliedAtAccess = canApplyFilterAtAccess(accessShape, candidate.prefixComponentMask())
					&& isFiniteNonNegative(accessShape.filterMultiplier())
					&& accessShape.filterMultiplier() < 1.0d;
			double rowsAfter = filterAppliedAtAccess ? rowsBefore * accessShape.filterMultiplier() : rowsBefore;
			if (!isFiniteNonNegative(rowsAfter)) {
				continue;
			}
			boolean directLookup = isExactDirectLookup(candidate.prefixComponentMask(), lookupComponentMask,
					rowsBefore, filterAppliedAtAccess);
			boolean exactStatementDirectLookup = directLookup
					&& isExactStatementLookup(candidate.prefixComponentMask(), lookupComponentMask);
			double plannedRowsBefore = exactStatementDirectLookup
					? Math.min(rowsBefore, DIRECT_LOOKUP_WORK_ROW_FLOOR)
					: rowsBefore;
			double plannedRowsAfter = exactStatementDirectLookup
					? Math.min(rowsAfter, DIRECT_LOOKUP_WORK_ROW_FLOOR)
					: rowsAfter;
			double workRows = directLookup ? Math.max(DIRECT_LOOKUP_WORK_ROW_FLOOR, plannedRowsAfter)
					: filterAppliedAtAccess ? rowsAfter : rowsBefore;
			if (!isFiniteNonNegative(workRows)) {
				continue;
			}
			AccessPathEstimate estimate = new AccessPathEstimate(workRows, plannedRowsBefore, plannedRowsAfter,
					candidate.indexFieldSequence(), candidate.prefixLength(), candidate.prefixComponentMask(),
					directLookup, coveredLookupComponentMask, missingLookupComponentMask, candidateCount);
			if (bestEstimate == null || compareAccessPathEstimate(estimate, bestEstimate) < 0) {
				bestEstimate = estimate;
			}
		}
		if (bestEstimate != null) {
			return bestEstimate;
		}
		return isFiniteNonNegative(factorRows)
				? new AccessPathEstimate(factorRows, factorRows, factorRows, "", 0, 0, false,
						lookupComponentMask, lookupComponentMask, candidateCount)
				: null;
	}

	private double rowsBeforeFilterLowerBound(double factorRows, double filterMultiplier) {
		if (!isFiniteNonNegative(factorRows)) {
			return Double.NaN;
		}
		if (isFiniteNonNegative(filterMultiplier) && filterMultiplier > 0.0d && filterMultiplier < 1.0d) {
			double rowsBeforeFilter = factorRows / filterMultiplier;
			if (isFiniteNonNegative(rowsBeforeFilter)) {
				return rowsBeforeFilter;
			}
		}
		return factorRows;
	}

	private int compareAccessPathEstimate(AccessPathEstimate left, AccessPathEstimate right) {
		if (left.directLookup() != right.directLookup()) {
			return left.directLookup() ? -1 : 1;
		}
		int workComparison = Double.compare(left.workRowsPerInvocation(), right.workRowsPerInvocation());
		if (workComparison != 0) {
			return workComparison;
		}
		int leftCoverage = Integer.bitCount(left.prefixComponentMask() & ~left.missingLookupComponentMask());
		int rightCoverage = Integer.bitCount(right.prefixComponentMask() & ~right.missingLookupComponentMask());
		int coverageComparison = Integer.compare(rightCoverage, leftCoverage);
		if (coverageComparison != 0) {
			return coverageComparison;
		}
		int prefixComparison = Integer.compare(right.prefixLength(), left.prefixLength());
		return prefixComparison;
	}

	private boolean isExactDirectLookup(int prefixComponentMask, int lookupComponentMask, double rowsBeforeFilter,
			boolean filterAppliedAtAccess) {
		if (lookupComponentMask == 0 || (prefixComponentMask & lookupComponentMask) != lookupComponentMask) {
			return false;
		}
		if (filterAppliedAtAccess) {
			return true;
		}
		int exactStatementMask = componentBit(Component.S) | componentBit(Component.P) | componentBit(Component.O);
		if ((prefixComponentMask & exactStatementMask) == exactStatementMask) {
			return true;
		}
		return rowsBeforeFilter <= DIRECT_LOOKUP_WORK_ROW_FLOOR;
	}

	private boolean isExactStatementLookup(int prefixComponentMask, int lookupComponentMask) {
		int exactStatementMask = componentBit(Component.S) | componentBit(Component.P) | componentBit(Component.O);
		return (prefixComponentMask & exactStatementMask) == exactStatementMask
				&& (lookupComponentMask & exactStatementMask) == exactStatementMask;
	}

	private int componentBit(Component component) {
		return 1 << component.ordinal();
	}

